package sandbox_test

import (
	"os"
	"strings"
	"testing"

	"github.com/novshi-tech/boid/internal/sandbox"
)

// readScripts returns the contents of the 3 scripts generated by Prepare.
// Scripts are auto-removed via t.Cleanup.
func readScripts(t *testing.T, outerPath string) (outer, setup, inner string) {
	t.Helper()
	prefix := strings.TrimSuffix(outerPath, "-outer.sh")
	innerPath := prefix + "-inner.sh"
	setupPath := prefix + "-setup.sh"
	t.Cleanup(func() {
		_ = os.Remove(outerPath)
		_ = os.Remove(setupPath)
		_ = os.Remove(innerPath)
	})

	outerBytes, err := os.ReadFile(outerPath)
	if err != nil {
		t.Fatalf("read outer: %v", err)
	}
	setupBytes, err := os.ReadFile(setupPath)
	if err != nil {
		t.Fatalf("read setup: %v", err)
	}
	innerBytes, err := os.ReadFile(innerPath)
	if err != nil {
		t.Fatalf("read inner: %v", err)
	}
	return string(outerBytes), string(setupBytes), string(innerBytes)
}

// minimalSpec returns a baseline Spec with HOME/WorkDir set to something sane
// so test cases only need to set the fields they're actually exercising.
func minimalSpec(id string) sandbox.Spec {
	return sandbox.Spec{
		ID:      id,
		WorkDir: "/home/user/proj",
		Env:     map[string]string{"HOME": "/home/user"},
		Argv:    []string{"/bin/true"},
	}
}

func TestPrepare_Basic(t *testing.T) {
	spec := minimalSpec("test-basic")
	spec.Env["BOID_TASK_ID"] = "task-1"
	spec.Argv = []string{"/home/user/proj/.boid/hooks/run.sh"}

	outerPath, err := sandbox.Prepare(spec)
	if err != nil {
		t.Fatalf("Prepare: %v", err)
	}
	_, _, inner := readScripts(t, outerPath)

	if !strings.Contains(inner, "export HOME=/home/user\n") {
		t.Errorf("inner: HOME export missing\n%s", inner)
	}
	if !strings.Contains(inner, "export BOID_TASK_ID=task-1\n") {
		t.Errorf("inner: BOID_TASK_ID missing\n%s", inner)
	}
	if !strings.Contains(inner, "\ncd /home/user/proj\n") {
		t.Errorf("inner: cd missing\n%s", inner)
	}
}

func TestPrepare_TTY(t *testing.T) {
	spec := minimalSpec("test-tty")
	spec.TTY = true

	outerPath, err := sandbox.Prepare(spec)
	if err != nil {
		t.Fatalf("Prepare: %v", err)
	}
	outer, _, _ := readScripts(t, outerPath)

	if !strings.Contains(outer, "exec 3>&2") {
		t.Errorf("outer should save stderr for TTY mode\n%s", outer)
	}
}

func TestPrepare_OuterScriptCleansUp(t *testing.T) {
	spec := minimalSpec("test-outer-cleanup")
	spec.RootDir = "/tmp/boid-root-test-cleanup"

	outerPath, err := sandbox.Prepare(spec)
	if err != nil {
		t.Fatalf("Prepare: %v", err)
	}
	outer, _, _ := readScripts(t, outerPath)

	// outer.sh must NOT exec-replace itself with pasta (exec would skip cleanup)
	if strings.Contains(outer, "exec pasta") {
		t.Errorf("outer should not use 'exec pasta' (prevents cleanup)\n%s", outer)
	}
	// outer.sh must clean up the root dir after pasta exits
	if !strings.Contains(outer, `rm -rf "$root_dir"`) {
		t.Errorf("outer should rm -rf $root_dir\n%s", outer)
	}
	// outer.sh must propagate pasta's exit code
	if !strings.Contains(outer, "exit $exit_code") {
		t.Errorf("outer should exit with pasta's exit code\n%s", outer)
	}
	// RootDir must be embedded in the script
	if !strings.Contains(outer, "/tmp/boid-root-test-cleanup") {
		t.Errorf("outer should embed the RootDir path\n%s", outer)
	}
	// outer.sh must skip cleanup on non-zero exit so that the diagnostic
	// retain path (cleanupSandboxAfterWait) can preserve the scripts.
	if !strings.Contains(outer, `if [ "$exit_code" -eq 0 ]; then`) {
		t.Errorf("outer should guard rm with exit_code==0\n%s", outer)
	}
}

