func TestPrepare_ArgvExec(t *testing.T) {
	spec := minimalSpec("test-argv-exec")
	spec.Argv = []string{"go", "test", "./..."}

	outerPath, err := sandbox.Prepare(spec)
	if err != nil {
		t.Fatalf("Prepare: %v", err)
	}
	_, _, inner := readScripts(t, outerPath)

	// No ExitScript → exec replaces the shell
	if !strings.Contains(inner, "\nexec go test ./...\n") {
		t.Errorf("inner: expected exec argv form\n%s", inner)
	}
	if strings.Contains(inner, "trap") {
		t.Errorf("inner: unexpected trap in exec mode\n%s", inner)
	}
}

func TestPrepare_ArgvWithExitScript(t *testing.T) {
	spec := minimalSpec("test-argv-trap")
	spec.Argv = []string{"/home/user/proj/.boid/hooks/run.sh"}
	spec.ExitScript = "boid job done my-job --exit-code $?"

	outerPath, err := sandbox.Prepare(spec)
	if err != nil {
		t.Fatalf("Prepare: %v", err)
	}
	_, _, inner := readScripts(t, outerPath)

	if !strings.Contains(inner, "trap 'boid job done my-job --exit-code $?' EXIT") {
		t.Errorf("inner: expected trap with ExitScript\n%s", inner)
	}
	if strings.Contains(inner, "\nexec /home/user/proj/.boid/hooks/run.sh\n") {
		t.Errorf("inner: should not use `exec` when ExitScript is set\n%s", inner)
	}
}

